\begin{theorem}
The generating functions for trees and non-superfluous trees are
\[
\varphi(x) = \theta(x) - \frac{x}{2} \left( \theta(x)^2 - \theta(x^2) \right), \tag{304b}
\]
\[
\psi(x) = \theta(x) - \frac{x}{2} \left( \theta(x)^2 + \theta(x^2) \right). \tag{304c}
\]
\end{theorem}

